/**
 * Nxcode SDK - Authentication Module
 */

import type { NxcodeUser, AuthResult, AuthStateCallback } from './types';

const STORAGE_KEY = 'nxcode_sdk_auth';

interface StoredAuth {
  token: string;
  refreshToken: string;
  expiresAt: string;
  user: NxcodeUser;
}

export class NxcodeAuth {
  private apiEndpoint: string;
  private appId: string;
  private user: NxcodeUser | null = null;
  private token: string | null = null;
  private refreshToken: string | null = null;
  private expiresAt: Date | null = null;
  private authCallbacks: AuthStateCallback[] = [];
  private popupWindow: Window | null = null;
  private messageHandler: ((event: MessageEvent) => void) | null = null;

  constructor(apiEndpoint: string, appId: string) {
    this.apiEndpoint = apiEndpoint;
    this.appId = appId;
    this.loadFromStorage();
    this.setupMessageListener();
  }

  /**
   * Initiate login flow via OAuth popup
   */
  async login(provider: 'google' | 'github' = 'google'): Promise<NxcodeUser> {
    return new Promise((resolve, reject) => {
      // Open popup
      const width = 500;
      const height = 600;
      const left = window.screenX + (window.outerWidth - width) / 2;
      const top = window.screenY + (window.outerHeight - height) / 2;

      const loginUrl = `${this.apiEndpoint}/api/sdk/auth/login?app_id=${this.appId}&provider=${provider}`;

      this.popupWindow = window.open(
        loginUrl,
        'nxcode_login',
        `width=${width},height=${height},left=${left},top=${top}`
      );

      if (!this.popupWindow) {
        reject(new Error('Failed to open login popup. Please allow popups for this site.'));
        return;
      }

      // Set up timeout
      const timeout = setTimeout(() => {
        this.popupWindow?.close();
        reject(new Error('Login timeout'));
      }, 120000); // 2 minute timeout

      // Wait for message from popup
      const handleMessage = (event: MessageEvent) => {
        if (event.data?.type !== 'NXCODE_SDK_AUTH') return;

        clearTimeout(timeout);
        window.removeEventListener('message', handleMessage);

        const result: AuthResult = event.data.payload;

        if (result.success && result.user && result.token) {
          this.setAuth(result);
          resolve(result.user);
        } else {
          reject(new Error(result.error || 'Login failed'));
        }
      };

      window.addEventListener('message', handleMessage);
    });
  }

  /**
   * Logout and clear session
   */
  async logout(): Promise<void> {
    try {
      if (this.token) {
        await fetch(`${this.apiEndpoint}/api/sdk/auth/logout`, {
          method: 'POST',
          headers: this.getHeaders(),
        });
      }
    } catch (error) {
      console.warn('Logout request failed:', error);
    }

    this.clearAuth();
  }

  /**
   * Get current user
   */
  getUser(): NxcodeUser | null {
    return this.user;
  }

  /**
   * Get current auth token
   */
  getToken(): string | null {
    // Check if token is expired
    if (this.expiresAt && new Date() > this.expiresAt) {
      // Token is expired, need to refresh
      // Start refresh in background but don't return the expired token
      this.refreshSession().catch(console.error);
      // Return null to force re-auth rather than using expired token
      return null;
    }
    return this.token;
  }

  /**
   * Get token, refreshing if needed (async version)
   */
  async getValidToken(): Promise<string | null> {
    if (this.expiresAt && new Date() > this.expiresAt) {
      await this.refreshSession();
    }
    return this.token;
  }

  /**
   * Register callback for auth state changes
   */
  onAuthStateChange(callback: AuthStateCallback): () => void {
    this.authCallbacks.push(callback);

    // Call immediately with current state
    callback(this.user);

    // Return unsubscribe function
    return () => {
      const index = this.authCallbacks.indexOf(callback);
      if (index > -1) {
        this.authCallbacks.splice(index, 1);
      }
    };
  }

  /**
   * Check if user is logged in
   */
  isLoggedIn(): boolean {
    return this.user !== null && this.token !== null;
  }

  /**
   * Refresh the current session
   */
  async refreshSession(): Promise<void> {
    if (!this.refreshToken) {
      this.clearAuth();
      return;
    }

    try {
      const response = await fetch(`${this.apiEndpoint}/api/sdk/auth/refresh`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'X-App-Id': this.appId,
        },
        body: JSON.stringify({ refreshToken: this.refreshToken }),
      });

      if (!response.ok) {
        throw new Error('Refresh failed');
      }

      const data = await response.json();
      this.setAuth({
        success: true,
        token: data.token,
        refreshToken: data.refreshToken,
        expiresAt: data.expiresAt,
        user: data.user,
      });
    } catch (error) {
      console.error('Session refresh failed:', error);
      this.clearAuth();
    }
  }

  /**
   * Fetch current user info from server
   */
  async fetchUser(): Promise<NxcodeUser | null> {
    if (!this.token) return null;

    try {
      const response = await fetch(`${this.apiEndpoint}/api/sdk/auth/me`, {
        headers: this.getHeaders(),
      });

      if (!response.ok) {
        if (response.status === 401) {
          await this.refreshSession();
          return this.user;
        }
        throw new Error('Failed to fetch user');
      }

      const user = await response.json();
      this.user = user;
      this.notifyAuthChange();
      this.saveToStorage();

      return user;
    } catch (error) {
      console.error('Failed to fetch user:', error);
      return null;
    }
  }

  // ==================== Private Methods ====================

  private setAuth(result: AuthResult): void {
    if (result.success && result.user && result.token) {
      this.user = result.user;
      this.token = result.token;
      this.refreshToken = result.refreshToken || null;
      this.expiresAt = result.expiresAt ? new Date(result.expiresAt) : null;

      this.saveToStorage();
      this.notifyAuthChange();
    }
  }

  private clearAuth(): void {
    this.user = null;
    this.token = null;
    this.refreshToken = null;
    this.expiresAt = null;

    localStorage.removeItem(`${STORAGE_KEY}_${this.appId}`);
    this.notifyAuthChange();
  }

  private saveToStorage(): void {
    if (this.user && this.token) {
      const data: StoredAuth = {
        token: this.token,
        refreshToken: this.refreshToken || '',
        expiresAt: this.expiresAt?.toISOString() || '',
        user: this.user,
      };
      localStorage.setItem(`${STORAGE_KEY}_${this.appId}`, JSON.stringify(data));
    }
  }

  private loadFromStorage(): void {
    try {
      const stored = localStorage.getItem(`${STORAGE_KEY}_${this.appId}`);
      if (stored) {
        const data: StoredAuth = JSON.parse(stored);
        this.token = data.token;
        this.refreshToken = data.refreshToken;
        this.expiresAt = data.expiresAt ? new Date(data.expiresAt) : null;
        this.user = data.user;

        // Check if expired
        if (this.expiresAt && new Date() > this.expiresAt) {
          this.refreshSession().catch(() => this.clearAuth());
        }
      }
    } catch (error) {
      console.warn('Failed to load auth from storage:', error);
    }
  }

  private notifyAuthChange(): void {
    for (const callback of this.authCallbacks) {
      try {
        callback(this.user);
      } catch (error) {
        console.error('Auth callback error:', error);
      }
    }
  }

  private setupMessageListener(): void {
    // Already set up message handling in login()
  }

  private getHeaders(): HeadersInit {
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      'X-App-Id': this.appId,
    };

    if (this.token) {
      headers['Authorization'] = `Bearer ${this.token}`;
    }

    return headers;
  }
}
